putMetric('AgentFootprint', 'OutputTokens', tokens.totalOutputTokens, 'Count');
putMetric('AgentFootprint', 'LLMCalls', tokens.totalCalls, 'Count');
putMetric('AgentFootprint', 'EstimatedCost', obs.cost(), 'None');

const tools = obs.tools();
