//   - Conditional branches at the TOP LEVEL before any LLM fires`}];function fV(){return uV.map(t=>({category:t,presets:dV.filter(e=>e.category===t.id)})).filter(t=>t.presets.length>0)}const z_={"llm-call":"✨",agent:"🤖",rag:"🔍",swarm:"🐝"},B_={"llm-call":"LLM Call",agent:"Agent",rag:"RAG",swarm:"Swarm"};function hV({activePresetId:t,onSelect:e,onViewCode:n,disabled:r}){const[o,a]=A.useState(!1),l=A.useRef(null),u=A.useMemo(()=>fV(),[]),d=A.useMemo(()=>{for(const f of u){const g=f.presets.find(m=>m.id===t);if(g)return g}return null},[u,t]);return A.useEffect(()=>{if(!o)return;const f=g=>{l.current&&!l.current.contains(g.target)&&a(!1)};return document.addEventListener("mousedown",f),()=>document.removeEventListener("mousedown",f)},[o]),A.useEffect(()=>{if(!o)return;const f=g=>{g.key==="Escape"&&a(!1)};return document.addEventListener("keydown",f),()=>document.removeEventListener("keydown",f)},[o]),y.jsxs("div",{className:"preset-selector",ref:l,children:[y.jsxs("button",{className:`preset-trigger ${o?"preset-trigger--open":""} ${d?"preset-trigger--active":""}`,onClick:()=>!r&&a(!o),disabled:r,type:"button",children:[d?y.jsxs(y.Fragment,{children:[y.jsx("span",{className:"preset-trigger-icon",children:z_[d.pattern]}),y.jsxs("span",{className:"preset-trigger-content",children:[y.jsx("span",{className:"preset-trigger-label",children:d.label}),y.jsx("span",{className:"preset-trigger-pattern",children:B_[d.pattern]})]})]}):y.jsx("span",{className:"preset-trigger-placeholder",children:"Choose an example to explore..."}),y.jsx("span",{className:`preset-trigger-chevron ${o?"preset-trigger-chevron--open":""}`,children:"▾"})]}),o&&y.jsx("div",{className:"preset-dropdown",children:u.map(({category:f,presets:g})=>y.jsxs("div",{className:"preset-group",children:[y.jsxs("div",{className:"preset-group-header",children:[y.jsx("span",{className:"preset-group-label",children:f.label}),y.jsx("span",{className:"preset-group-desc",children:f.description})]}),g.map(m=>y.jsxs("button",{cla